#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#define BLOCK_SIZE 16

int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

__kernel void nw_kernel1(__global int* referrence, __global int* input_itemsets, __global int* output_itemsets,
                         __local int* input_itemsets_l, __local int* reference_l,
                         const int max_cols, const int penalty, const int blk,
                         const int block_width, const int worksize,
                         const int offset_r, const int offset_c) {
    int b_index_x = get_global_id(0) / BLOCK_SIZE;
    if (b_index_x >= blk) return;
    int b_index_y = blk - 1 - b_index_x;

    // Load reference_l and input_itemsets_l to local memory by work-items collaboratively
    // Use get_local_id(0) for indexing within block
    int local_id = get_local_id(0);
    int local_size = get_local_size(0);

    // Load reference_l: BLOCK_SIZE * BLOCK_SIZE
    for (int idx = local_id; idx < BLOCK_SIZE * BLOCK_SIZE; idx += local_size) {
        int i = idx / BLOCK_SIZE;
        int j = idx % BLOCK_SIZE;
        reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
    }

    // Load input_itemsets_l: (BLOCK_SIZE+1)*(BLOCK_SIZE+1)
    for (int idx = local_id; idx < (BLOCK_SIZE + 1) * (BLOCK_SIZE + 1); idx += local_size) {
        int i = idx / (BLOCK_SIZE + 1);
        int j = idx % (BLOCK_SIZE + 1);
        input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute the block diagonally sequentially inside each work-item
    // Because data dependencies are intra-block, we must compute sequentially within the block
    if (local_id == 0) {
        for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
            for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
            }
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Write back to global memory collaboratively
    for (int idx = local_id; idx < BLOCK_SIZE * BLOCK_SIZE; idx += local_size) {
        int i = idx / BLOCK_SIZE;
        int j = idx % BLOCK_SIZE;
        input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
    }
}

__kernel void nw_kernel2(__global int* referrence, __global int* input_itemsets, __global int* output_itemsets,
                         __local int* input_itemsets_l, __local int* reference_l,
                         const int max_cols, const int penalty, const int blk,
                         const int block_width, const int worksize,
                         const int offset_r, const int offset_c) {
    int b_index_x = get_global_id(0) / BLOCK_SIZE + (blk - 1);
    if (b_index_x >= block_width) return;
    int b_index_y = block_width + blk - 2 - b_index_x;

    int local_id = get_local_id(0);
    int local_size = get_local_size(0);

    // Load reference_l: BLOCK_SIZE * BLOCK_SIZE
    for (int idx = local_id; idx < BLOCK_SIZE * BLOCK_SIZE; idx += local_size) {
        int i = idx / BLOCK_SIZE;
        int j = idx % BLOCK_SIZE;
        reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
    }

    // Load input_itemsets_l: (BLOCK_SIZE+1)*(BLOCK_SIZE+1)
    for (int idx = local_id; idx < (BLOCK_SIZE + 1) * (BLOCK_SIZE + 1); idx += local_size) {
        int i = idx / (BLOCK_SIZE + 1);
        int j = idx % (BLOCK_SIZE + 1);
        input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (local_id == 0) {
        for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
            for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
            }
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (int idx = local_id; idx < BLOCK_SIZE * BLOCK_SIZE; idx += local_size) {
        int i = idx / BLOCK_SIZE;
        int j = idx % BLOCK_SIZE;
        input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
    }
}
